firmware_template.source:
#include "wifi_mesh.h"
#include <painlessMesh.h>
static painlessMesh mesh;
static mesh_cb _cb=nullptr;
void _meshRecv(uint32_t from,String&msg){if(_cb)_cb(from,msg.c_str());}
void mesh_setup(const char*p,const char*pw){mesh.init(p,pw,5555);mesh.onReceive(_meshRecv);Serial.printf("[mesh] OK node=%u\n",mesh.getNodeId());}
void mesh_loop(){mesh.update();}
void mesh_broadcast(const char*m){mesh.sendBroadcast(m);}
uint32_t mesh_get_node_id(){return mesh.getNodeId();}
int mesh_node_count(){return mesh.getNodeList().size();}
void mesh_on_receive(mesh_cb cb){_cb=cb;}
